// Get all delete buttons
const deleteButtons = document.querySelectorAll('.delete-button');

// Add event listener to each delete button
deleteButtons.forEach(button =&gt; {
  button.addEventListener('click', async () =&gt; {
    // Get the card ID or whatever identifier is needed for the delete request
    const cardId = button.dataset.cardId;

    try {
      // Send a DELETE request to the backend route
      const response = await fetch(`/api/cards/${cardId}`, {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (response.ok) {
        // Handle successful deletion
        console.log(`Card ${cardId} deleted successfully`);
      } else {
        // Handle error
        console.error(`Error deleting card ${cardId}: ${response.statusText}`);
      }
    } catch (error) {
      console.error(`Error deleting card ${cardId}: ${error.message}`);
    }
  });
});
```

