app.get('/api/cards', (req, res) =&gt; {
  console.log('GET /api/cards requested');
  res.status(200).json(cardsData);
});

// DELETE a specific card by ID
app.delete('/api/cards/:cardId', (req, res) =&gt; {
  const cardIdToDelete = req.params.cardId;
  console.log(`DELETE /api/cards/${cardIdToDelete} requested`);

  const initialLength = cardsData.length;
  // Filter out the card to be deleted
  cardsData = cardsData.filter(card =&gt; card.id !== cardIdToDelete);

  if (cardsData.length &lt; initialLength) {
    // Card was found and removed
    console.log(`Card ${cardIdToDelete} successfully deleted.`);
    res.status(200).json({ message: `Card with ID ${cardIdToDelete} deleted successfully.` });
  } else {
    // Card not found
    console.log(`Card ${cardIdToDelete} not found.`);
    res.status(404).json({ message: `Card with ID ${cardIdToDelete} not found.` });
  }
});

// --- Start Server ---
app.listen(port, () =&gt; {
  console.log(`Backend server running on port ${port}`);
});
```
