import React, { useState, useEffect } from 'react';
import Card from './Card'; // Make sure the path is correct

function CardList() {
  const [cards, setCards] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Fetch initial cards
  useEffect(() =&gt; {
    const fetchCards = async () =&gt; {
      try {
        // Assuming your API endpoint for fetching cards is '/api/cards'
        const response = await fetch('/api/cards');
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();
        setCards(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };
    fetchCards();
  }, []);

  // Function to handle card deletion
  const handleDeleteCard = async (cardId) =&gt; {
    // Optional: Add a confirmation dialog for the user
    if (!window.confirm(`Are you sure you want to delete card with ID: ${cardId}?`)) {
      return; // User cancelled the action
    }

    try {
      // Make the DELETE request to your backend
      // Ensure this URL matches your backend route
      const response = await fetch(`/api/cards/${cardId}`, {
        method: 'DELETE',
        // If your backend requires authentication (e.g., JWT tokens), add headers here:
        // headers: { 'Authorization': 'Bearer YOUR_AUTH_TOKEN' }
      });

      if (response.ok) {
        // If deletion was successful, update the local state by filtering out the deleted card
        setCards(cards.filter(card =&gt; card.id !== cardId));
        console.log(`Card ${cardId} deleted successfully.`);
        // Optionally, show a success notification to the user
      } else {
        // Handle backend errors
        const errorData = await response.json(); // Try to get error details from backend response
        console.error(`Failed to delete card ${cardId}. Server responded with:`, response.status, errorData);
        setError(`Failed to delete card. ${errorData.message || response.statusText}`);
        // Optionally, show an error notification to the user
      }
    } catch (err) {
      // Handle network errors
      console.error(`Network error while deleting card ${cardId}:`, err);
      setError(`Network error: ${err.message}`);
      // Optionally, show an error notification to the user
    }
  };

  if (loading) return &lt;p&gt;Loading cards...&lt;/p&gt;;
  if (error) return &lt;p&gt;Error: {error}&lt;/p&gt;;

  return (
    &lt;div&gt;
      &lt;h2&gt;Your Kanban Board&lt;/h2&gt;
      {cards.length === 0 ? (
        &lt;p&gt;No cards available. Add some!&lt;/p&gt;
      ) : (
        cards.map(card =&gt; (
          &lt;Card
            key={card.id} // Essential for React list rendering
            card={card}
            onDelete={handleDeleteCard} // Pass the delete handler
          /&gt;
        ))
      )}
    &lt;/div&gt;
  );
}

export default CardList;
